"""
solution.py

Reads numbers.txt and prints how many integers are even.
"""

def main():
    try:
        with open("numbers.txt", "r") as f:
            lines = f.readlines()
    except FileNotFoundError:
        print("numbers.txt not found.")
        return

    count_even = 0
    for line in lines:
        stripped = line.strip()
        if not stripped:
            continue
        try:
            num = int(stripped)
        except ValueError:
            # Skip non-integer lines
            continue
        if num % 2 == 0:
            count_even += 1

    print(count_even)

if __name__ == "__main__":
    main()

